describe("pollAgentSessionEvents", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
        vi.useFakeTimers();
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
        vi.useRealTimers();
    });
    it("emits events and advances the cursor across polls", async () => {
        const e1 = makeNavigateEvent("1735689600000-0", "/a");
        const e2 = makeNavigateEvent("1735689600001-0", "/b");
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [e1, e2] }))
            .mockResolvedValueOnce(jsonResponse({ events: [] }));
        const events = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 100,
            abortSignal: abort.signal,
            onEvent: (event) => events.push(event),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(100);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(events).toEqual([e1, e2]);
        expect(fetchMock).toHaveBeenCalledTimes(2);
        const firstUrl = fetchMock.mock.calls[0][0];
        const secondUrl = fetchMock.mock.calls[1][0];
        expect(firstUrl).toContain(`session=${SESSION_ID}`);
        expect(firstUrl).not.toContain("since=");
        expect(secondUrl).toContain(`since=${encodeURIComponent(e2.id)}`);
    });
    it("invokes onBrowserStatus when browserConnected is in the response", async () => {
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [], browserConnected: true }))
            .mockResolvedValueOnce(jsonResponse({ events: [], browserConnected: false }));
        const statuses = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 50,
            abortSignal: abort.signal,
            onEvent: () => { },
            onBrowserStatus: (connected) => statuses.push(connected),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(50);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(statuses).toEqual([true, false]);
    });
    it("respects startCursor on the first fetch", async () => {
        const start = "1735689600000-0";
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            startCursor: start,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        const firstUrl = fetchMock.mock.calls[0][0];
        expect(firstUrl).toContain(`since=${encodeURIComponent(start)}`);
    });
    it("calls onError on non-2xx responses but keeps looping", async () => {
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ error: "boom" }, { status: 500 }))
            .mockResolvedValueOnce(jsonResponse({ events: [] }));
        const errors = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 50,
            abortSignal: abort.signal,
            onEvent: () => { },
            onError: (err) => errors.push(err),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(50);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(errors).toHaveLength(1);
        expect(errors[0].message).toMatch(/500/);
        expect(fetchMock).toHaveBeenCalledTimes(2);
    });
    it("terminates immediately when abort fires before the first fetch", async () => {
        const abort = new AbortController();
        abort.abort();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await loop;
        expect(fetchMock).not.toHaveBeenCalled();
    });
    it("does not leak abort listeners across poll iterations", async () => {
        fetchMock.mockImplementation(() => jsonResponse({ events: [] }));
        const abort = new AbortController();
        const addSpy = vi.spyOn(abort.signal, "addEventListener");
        const removeSpy = vi.spyOn(abort.signal, "removeEventListener");
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 50,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        for (let i = 0; i < 20; i++) {
            await vi.advanceTimersByTimeAsync(50);
            await vi.advanceTimersByTimeAsync(0);
        }
        const addCount = addSpy.mock.calls.filter((c) => c[0] === "abort").length;
        const removeCount = removeSpy.mock.calls.filter((c) => c[0] === "abort").length;
        expect(removeCount).toBeGreaterThanOrEqual(addCount - 1);
        abort.abort();
        await loop;
    });
    it("sends the API key as a Bearer Authorization header", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        const init = fetchMock.mock.calls[0][1];
        expect(init.headers.Authorization).toBe(`Bearer ${API_KEY}`);
    });
});
describe("fetchStreamTip", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    const client = {
        serviceUrl: SERVICE_URL,
        apiKey: API_KEY,
        sessionId: SESSION_ID,
    };
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("returns undefined for an empty stream", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        await expect(fetchStreamTip(client)).resolves.toBeUndefined();
    });
    it("returns the last event id of a single-page stream", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [{ id: "100-0" }, { id: "200-5" }] }));
        await expect(fetchStreamTip(client)).resolves.toBe("200-5");
        expect(fetchMock).toHaveBeenCalledOnce();
    });
    it("pages past a full batch to find the true tail", async () => {
        // A full first page means the stream may continue: the single-read tip
        // would be stale, so the helper must follow `since` until a partial page.
        const fullPage = Array.from({ length: 500 }, (_, i) => ({
            id: `${i + 1}-0`,
        }));
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: fullPage }))
            .mockResolvedValueOnce(jsonResponse({ events: [{ id: "501-0" }, { id: "502-0" }] }));
        await expect(fetchStreamTip(client)).resolves.toBe("502-0");
        expect(fetchMock).toHaveBeenCalledTimes(2);
        const secondUrl = new URL(fetchMock.mock.calls[1][0]);
        expect(secondUrl.searchParams.get("since")).toBe("500-0");
    });
    it("returns undefined when the stream is unreachable", async () => {
        fetchMock.mockRejectedValueOnce(new Error("network down"));
        await expect(fetchStreamTip(client)).resolves.toBeUndefined();
    });
});
describe("navigateStudioAndAwaitAck", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
        vi.useFakeTimers();
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
        vi.useRealTimers();
    });
    // Mock ordering note: `navigateStudioAndAwaitAck` fetches the stream tip
    // first (so the ack wait ignores replayed history), then awaits the
    // navigate POST, then starts the poll loop via `awaitNavigateAck`. So the
    // first fetch is the tip GET, the second is the navigate POST, and the
    // third is the ack poll GET. Order the mocks accordingly.
    it("resolves acked: true when studio:navigated arrives for the matching path", async () => {
        const path = "/studio/trace-plan/abc";
        fetchMock
            // First fetch: stream-tip GET (empty stream).
            .mockResolvedValueOnce(jsonResponse({ events: [] }))
            // Second fetch: navigate POST.
            .mockResolvedValueOnce(jsonResponse({ id: "evt-1" }))
            // Third fetch: poll GET — returns the matching studio:navigated ack.
            .mockResolvedValueOnce(jsonResponse({
            events: [
                { id: "1735689600000-0", type: "studio:navigated", data: { path } },
            ],
        }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({ acked: true });
    });
    it("waits for a FRESH ack: the ack poll starts after the pre-push stream tip", async () => {
        // A historical studio:navigated for the same path must never count as the
        // ack (it would false-ack a navigation a dead window never processed).
        const path = "/studio/trace-plan/abc";
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [{ id: "900-0" }] }))
            .mockResolvedValueOnce(jsonResponse({ id: "evt-1" }))
            .mockResolvedValueOnce(jsonResponse({
            events: [{ id: "901-0", type: "studio:navigated", data: { path } }],
        }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({ acked: true });
        // The ack poll (third fetch) must start strictly after the tip.
        const ackPollUrl = new URL(fetchMock.mock.calls[2][0]);
        expect(ackPollUrl.searchParams.get("since")).toBe("900-0");
    });
    it("resolves acked: false / window-closed when the window tears down mid-wait", async () => {
        const path = "/studio/trace-plan/abc";
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [] }))
            .mockResolvedValueOnce(jsonResponse({ id: "evt-1" }))
            .mockResolvedValueOnce(jsonResponse({
            events: [
                { id: "1735689600000-0", type: "studio:window-closed", data: {} },
            ],
        }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({
            acked: false,
            reason: "window-closed",
        });
    });
    it("ignores session-ended/session-closed mid-wait (an ended window can still ack)", async () => {
        // The end-session flow emits session-ended (and the close page emits
        // session-closed) before a window.close() the browser can refuse, so
        // neither means the window is gone — a later navigated ack must still win.
        const path = "/studio/trace-plan/abc";
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [] }))
            .mockResolvedValueOnce(jsonResponse({ id: "evt-1" }))
            .mockResolvedValueOnce(jsonResponse({
            events: [
                { id: "1735689600000-0", type: "studio:session-ended", data: {} },
                { id: "1735689600000-1", type: "studio:session-closed", data: {} },
            ],
        }))
            .mockResolvedValueOnce(jsonResponse({
            events: [
                { id: "1735689600001-0", type: "studio:navigated", data: { path } },
            ],
        }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        // Next poll tick delivers the ack.
        await vi.advanceTimersByTimeAsync(1_500);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({ acked: true });
    });
    it("resolves acked: false / timeout when no ack arrives and ping-pong also fails", async () => {
        const path = "/studio/trace-plan/abc";
        fetchMock.mockImplementation(() => jsonResponse({ events: [] }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 1_000 });
        // Drain the navigate push + first poll cycle, then jump past ack deadline.
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(1_001);
        // Drain the ping POST + first pong poll cycle.
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        // Jump past the ping-pong deadline.
        await vi.advanceTimersByTimeAsync(5_001);
        await expect(promise).resolves.toEqual({
            acked: false,
            reason: "timeout",
        });
    });
    it("falls back to ping-pong and resolves acked: true when pong arrives after navigate ack timeout", async () => {
        const path = "/studio/trace-plan/abc";
        let callCount = 0;
        fetchMock.mockImplementation(() => {
            callCount++;
            if (callCount === 1) {
                return jsonResponse({ id: "evt-nav" });
            }
            // Pong poll: return a matching pong after the ping POST. Call order is
            // 1 tip GET, 2 navigate POST, 3 ack poll, 4 ping POST, 5 pong poll.
            // (Call 1 returning {id} is harmless: the tip helper reads `events` and
            // treats its absence as an empty stream.)
            if (callCount === 5) {
                return jsonResponse({
                    events: [
                        {
                            id: "1735689600000-1",
                            type: "studio:pong",
                            data: { ts: Date.now(), replyTo: Date.now() },
                        },
                    ],
                });
            }
            return jsonResponse({ events: [] });
        });
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 1_000 });
        // Tip GET + navigate POST + ack poll (empty).
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        // Ack deadline fires.
        await vi.advanceTimersByTimeAsync(1_001);
        // Ping POST + pong poll (returns matching pong).
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({ acked: true });
    });
    it("resolves acked: false / blocked when studio:navigation-blocked arrives", async () => {
        const path = "/studio/trace-plan/plan-123";
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [] }))
            .mockResolvedValueOnce(jsonResponse({ id: "evt-1" }))
            .mockResolvedValueOnce(jsonResponse({
            events: [
                {
                    id: "1735689600000-0",
                    type: "studio:navigation-blocked",
                    data: {
                        path,
                        reason: "Plan not found",
                    },
                },
            ],
        }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({
            acked: false,
            reason: "blocked",
            blockedReason: "Plan not found",
        });
    });
    it("resolves acked: false / invalid-route when path is not in the studio route whitelist", async () => {
        const path = "/studio/nonexistent";
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await expect(promise).resolves.toEqual({
            acked: false,
            reason: "invalid-route",
        });
    });
    it("matches ack by pathname only, ignoring query params in the requested path", async () => {
        const path = "/studio/experiments?testRunIds=run-1,run-2";
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [] }))
            .mockResolvedValueOnce(jsonResponse({ id: "evt-1" }))
            .mockResolvedValueOnce(jsonResponse({
            events: [
                {
                    id: "1735689600000-0",
                    type: "studio:navigated",
                    data: { path: "/studio/experiments" },
                },
            ],
        }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({ acked: true });
    });
    it("resolves acked: false / push-failed when the navigate POST throws", async () => {
        const path = "/studio/trace-plan/abc";
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [] }))
            .mockRejectedValueOnce(new Error("network down"));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({
            acked: false,
            reason: "push-failed",
        });
    });
});
describe("isStudioBrowserConnected", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("returns true when the server reports browserConnected", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [], browserConnected: true }));
        const got = await isStudioBrowserConnected({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(got).toBe(true);
    });
    it("returns false when browserConnected is missing or false", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        const got = await isStudioBrowserConnected({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(got).toBe(false);
    });
    it("returns false on non-2xx", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ error: "forbidden" }, { status: 403 }));
        const got = await isStudioBrowserConnected({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(got).toBe(false);
    });
    it("returns false when the fetch throws", async () => {
        fetchMock.mockRejectedValueOnce(new Error("network down"));
        const got = await isStudioBrowserConnected({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(got).toBe(false);
    });
});
