describe("sendPong", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("pushes an agent:pong event with ts and replyTo", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ id: "1735689600000-0" }));
        const pingTs = 1735689600000;
        const result = await sendPong({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, pingTs);
        expect(result).toEqual({ id: "1735689600000-0" });
        const [, init] = fetchMock.mock.calls[0];
        const body = JSON.parse(init.body);
        expect(body.type).toBe("agent:pong");
        expect(body.data.replyTo).toBe(pingTs);
        expect(typeof body.data.ts).toBe("number");
    });
});
describe("pollAgentSessionEvents auto-pong", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
        vi.useFakeTimers();
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
        vi.useRealTimers();
    });
    it("auto-replies agent:pong when a studio:ping event is received", async () => {
        const pingTs = 1735689600000;
        const pingEvent = {
            id: "1735689600000-0",
            type: "studio:ping",
            data: { ts: pingTs },
        };
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [pingEvent] }))
            .mockResolvedValueOnce(jsonResponse({ id: "pong-1" }))
            .mockResolvedValueOnce(jsonResponse({ events: [] }));
        const events = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 100,
            abortSignal: abort.signal,
            onEvent: (event) => events.push(event),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(events).toEqual([pingEvent]);
        const pongCall = fetchMock.mock.calls.find(([, init]) => {
            if (!init?.body) {
                return false;
            }
            const body = JSON.parse(init.body);
            return body.type === "agent:pong";
        });
        expect(pongCall).toBeDefined();
        const pongBody = JSON.parse(pongCall[1].body);
        expect(pongBody.data.replyTo).toBe(pingTs);
    });
});
describe("pollLoginEvents", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("polls the unauthenticated sessions/poll endpoint without auth headers", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({
            events: [
                {
                    id: "1-0",
                    type: "studio:authenticated",
                    data: { token: "tok-abc" },
                },
            ],
        }));
        const ac = new AbortController();
        const token = await pollLoginEvents({
            serviceUrl: SERVICE_URL,
            sessionId: SESSION_ID,
            abortSignal: ac.signal,
        });
        expect(token).toBe("tok-abc");
        const [calledUrl, init] = fetchMock.mock.calls[0];
        expect(calledUrl).toContain("/api/studio/sessions/poll");
        expect(calledUrl).toContain(`session=${SESSION_ID}`);
        expect(init.headers).toBeUndefined();
    });
    it("skips non-authenticated events and keeps polling", async () => {
        fetchMock
            .mockResolvedValueOnce(jsonResponse({
            events: [{ id: "1-0", type: "studio:auth-required", data: {} }],
        }))
            .mockResolvedValueOnce(jsonResponse({
            events: [
                {
                    id: "2-0",
                    type: "studio:authenticated",
                    data: { token: "tok-def" },
                },
            ],
        }));
        const ac = new AbortController();
        const token = await pollLoginEvents({
            serviceUrl: SERVICE_URL,
            sessionId: SESSION_ID,
            intervalMs: 10,
            abortSignal: ac.signal,
        });
        expect(token).toBe("tok-def");
        expect(fetchMock).toHaveBeenCalledTimes(2);
    });
    it("passes the since cursor on subsequent polls", async () => {
        fetchMock
            .mockResolvedValueOnce(jsonResponse({
            events: [{ id: "5-0", type: "studio:not-member", data: {} }],
        }))
            .mockResolvedValueOnce(jsonResponse({
            events: [
                {
                    id: "6-0",
                    type: "studio:authenticated",
                    data: { token: "tok-ghi" },
                },
            ],
        }));
        const ac = new AbortController();
        await pollLoginEvents({
            serviceUrl: SERVICE_URL,
            sessionId: SESSION_ID,
            intervalMs: 10,
            abortSignal: ac.signal,
        });
        const secondUrl = fetchMock.mock.calls[1][0];
        expect(secondUrl).toContain("since=5-0");
    });
    it("throws when aborted", async () => {
        fetchMock.mockResolvedValue(jsonResponse({ events: [] }));
        const ac = new AbortController();
        const promise = pollLoginEvents({
            serviceUrl: SERVICE_URL,
            sessionId: SESSION_ID,
            intervalMs: 10,
            abortSignal: ac.signal,
        });
        setTimeout(() => ac.abort(), 50);
        await expect(promise).rejects.toThrow("Login polling aborted");
    });
});
